import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { AppStoreService } from '../../services/app-store.service';
import { AppDefinition } from '../../models/app-store.models';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import {
  Observable,
  BehaviorSubject,
  Subject,
  combineLatest,
  map,
  debounceTime,
  startWith,
  catchError,
  finalize,
  of,
  tap,
  shareReplay,
} from 'rxjs';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { SelectModule } from 'primeng/select';
import { TagModule } from 'primeng/tag';
import { RatingModule } from 'primeng/rating';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIconModule } from 'primeng/inputicon';
import { CardModule } from 'primeng/card';
import { DEFAULT_SYSTEM_ID } from '../../../../core/models';
import { IdName } from '../../../../api';

@Component({
  selector: 'app-app-marketplace',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ButtonModule,
    InputTextModule,
    SelectModule,
    TagModule,
    RatingModule,
    IconFieldModule,
    InputIconModule,
    CardModule,
  ],
  templateUrl: './app-marketplace.component.html',
  styleUrls: ['./app-marketplace.component.scss'],
})
export class AppMarketplaceComponent {
  apps$: Observable<AppDefinition[]>;
  loading$ = new BehaviorSubject<boolean>(true);
  error$ = new BehaviorSubject<string | null>(null);

  private readonly searchInput$ = new Subject<string>();
  searchQuery$ = this.searchInput$.pipe(debounceTime(250), startWith(''));
  categoryFilter$ = new BehaviorSubject<string>('All');
  sortOrder$ = new BehaviorSubject<string>('popular'); // popular, newest, rating

  categories = [
    'All',
    'Fleet Management',
    'Safety',
    'Maintenance',
    'Reporting',
  ];

  sortOptions = [
    { label: 'Most Popular', value: 'popular' },
    { label: 'Newest Arrivals', value: 'newest' },
    { label: 'Highest Rated', value: 'rating' },
  ];

  private readonly appStoreService = inject(AppStoreService);
  private readonly authDataService = inject(AuthDataService);

  readonly isAdmin = this.authDataService
    .getUserProfile()
    ?.roles?.some((role: IdName) => role.id === DEFAULT_SYSTEM_ID);

  constructor() {
    const allApps$ = this.appStoreService.getApps().pipe(
      tap(() => this.loading$.next(true)),
      catchError(() => {
        this.error$.next('Unable to load apps. Please try again.');
        return of([] as AppDefinition[]);
      }),
      finalize(() => this.loading$.next(false)),
      shareReplay(1),
    );

    this.apps$ = combineLatest([
      allApps$,
      this.searchQuery$,
      this.categoryFilter$,
      this.sortOrder$,
    ]).pipe(
      map(([apps, query, category, sort]) => {
        const filtered = apps.filter((app) => {
          const matchesSearch =
            app.name.toLowerCase().includes(query.toLowerCase()) ||
            app.shortDescription.toLowerCase().includes(query.toLowerCase());
          const matchesCategory =
            category === 'All' || app.categories.includes(category);
          return matchesSearch && matchesCategory;
        });

        // Sort
        return filtered.sort((a, b) => {
          if (sort === 'popular') return b.installCount - a.installCount;
          if (sort === 'newest')
            return (
              new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
            );
          if (sort === 'rating') return b.averageRating - a.averageRating;
          return 0;
        });
      }),
      shareReplay(1),
    );

    // Subscribe eagerly to trigger the HTTP request
    this.apps$.subscribe();
  }

  onSearch(query: string) {
    this.searchInput$.next(query);
  }

  onCategorySelect(category: string) {
    this.categoryFilter$.next(category);
  }

  onSortChange(sort: string) {
    this.sortOrder$.next(sort);
  }

  statusSeverity(
    status: AppDefinition['status'],
  ): 'success' | 'info' | 'warn' | 'danger' | 'secondary' {
    if (status === 'APPROVED') return 'success';
    if (status === 'PENDING_REVIEW') return 'warn';
    if (status === 'DRAFT') return 'secondary';
    if (status === 'SUSPENDED') return 'danger';
    return 'info';
  }

  statusLabel(status: AppDefinition['status']): string {
    return status
      .toLowerCase()
      .split('_')
      .map((part) => part[0].toUpperCase() + part.slice(1))
      .join(' ');
  }
}
